// ============================================
// CONSTRUCTION DE L'ARBORESCENCE NESTED
// ============================================

const response = $input.first().json;
const allItems = response.files || [];

// Maps pour organiser
const foldersMap = new Map();
const filesMap = new Map();
const childrenMap = new Map();

// Classifier tous les éléments
for (const item of allItems) {
  const parentId = (item.parents && item.parents.length > 0) ? item.parents[0] : 'root';

  // Ajouter à la liste des enfants du parent
  if (!childrenMap.has(parentId)) {
    childrenMap.set(parentId, []);
  }
  childrenMap.get(parentId).push(item.id);

  if (item.mimeType === 'application/vnd.google-apps.folder') {
    foldersMap.set(item.id, {
      id: item.id,
      nom: item.name,
      parentId: parentId
    });
  } else {
    filesMap.set(item.id, {
      id: item.id,
      nom: item.name,
      mimeType: item.mimeType,
      parentId: parentId
    });
  }
}

// Fonction récursive pour construire l'arbre
function buildTree(folderId) {
  const result = { sousDossiers: [], fichiers: [] };
  const children = childrenMap.get(folderId) || [];

  for (const childId of children) {
    if (foldersMap.has(childId)) {
      const folder = foldersMap.get(childId);
      const content = buildTree(childId);
      result.sousDossiers.push({
        id: folder.id,
        nom: folder.nom,
        type: 'dossier',
        sousDossiers: content.sousDossiers,
        fichiers: content.fichiers
      });
    } else if (filesMap.has(childId)) {
      const file = filesMap.get(childId);
      result.fichiers.push({
        id: file.id,
        nom: file.nom,
        type: 'fichier',
        mimeType: file.mimeType
      });
    }
  }
  return result;
}

// Trouver les éléments racine
const rootFolders = [];
const rootFiles = [];

for (const [id, folder] of foldersMap) {
  if (folder.parentId === 'root' || !foldersMap.has(folder.parentId)) {
    const content = buildTree(id);
    rootFolders.push({
      id: folder.id,
      nom: folder.nom,
      type: 'dossier',
      sousDossiers: content.sousDossiers,
      fichiers: content.fichiers
    });
  }
}

for (const [id, file] of filesMap) {
  if (file.parentId === 'root' || !foldersMap.has(file.parentId)) {
    rootFiles.push({
      id: file.id,
      nom: file.nom,
      type: 'fichier',
      mimeType: file.mimeType
    });
  }
}

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    statistiques: {
      totalDossiers: foldersMap.size,
      totalFichiers: filesMap.size,
      dossiersRacine: rootFolders.length,
      fichiersRacine: rootFiles.length
    },
    arborescence: {
      dossiers: rootFolders,
      fichiers: rootFiles
    }
  }
}];
